import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/macos-password-prompt.BkxO9RJk.js";const s=JSON.parse(`{"title":"Instalando o Fabric no macOS","description":"Um guia passo a passo de como instalar o Java no macOS.","frontmatter":{"title":"Instalando o Fabric no macOS","description":"Um guia passo a passo de como instalar o Java no macOS.","authors":["dexman545","ezfe"],"next":false,"files":[]},"headers":[],"relativePath":"pt_br/players/installing-java/macos.md","filePath":"translated/pt_br/players/installing-java/macos.md","lastUpdated":1770561656000}`);var c={name:`pt_br/players/installing-java/macos.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Instalando o Fabric no macOS <a class="header-anchor" href="#h1" aria-label="Permalink to “Instalando o Fabric no macOS”">​</a></h1><p>Esse guia irá ajudá-lo com a Instalação do Java 21 no macOS.</p><p>O Iniciador do Minecraft vem com o seu próprio Java instalado. Então, essa sessão somente é relevante, se você quiser usar o instalador baseado em &quot;.jar&quot; ou se você quiser usar o Servidor de Minecraft &quot;.jar&quot;.</p><h2 id="1-check-if-java-is-already-installed" tabindex="-1">1. Verifique se o Java já está instalado <a class="header-anchor" href="#1-check-if-java-is-already-installed" aria-label="Permalink to “1. Verifique se o Java já está instalado”">​</a></h2><p>No terminal (localizado em <code>/Aplicações/terminal.app</code>) digite o seguinte comando, e pressione <kbd>Enter</kbd>:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/usr/libexec/java_home</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 21</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)/bin/java --version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Você deve ver algo como isso:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>openjdk 21.0.9 2025-10-21 LTS</span></span>
<span class="line"><span>OpenJDK Runtime Environment Temurin-21.0.9+10 (build 21.0.9+10-LTS)</span></span>
<span class="line"><span>OpenJDK 64-Bit Server VM Temurin-21.0.9+10 (build 21.0.9+10-LTS, mixed mode, sharing)</span></span></code></pre></div><p>Perceba o número da versão: No exemplo acima é <code>21.0.9</code>.</p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Para usar o Minecraft 1.21.11, você precisará ter, pelo menos, o Java 21 instalado.</p><p>Se esse comando exibir qualquer versão inferior a 21, você precisará atualizar o seu Java; continue lendo essa página.</p></div><h2 id="2-downloading-and-installing-java" tabindex="-1">2. Baixando and Instalando o Java 21 <a class="header-anchor" href="#2-downloading-and-installing-java" aria-label="Permalink to “2. Baixando and Instalando o Java 21”">​</a></h2><p>Nós recomendamos usar <a href="https://adoptium.net/temurin/releases?version=21&amp;os=mac&amp;arch=any&amp;mode=filter" target="_blank" rel="noreferrer">Arquitetura Adoptium no OpenJDK 21</a>:</p><p><img src="/assets/players/installing-java/macos-download-java.png" alt="Página para baixar o Temurin Java" loading="lazy"></p><p>Certifique-se de selecionar a versão &quot;21 - LTS&quot; e escolha o formato de instalação <code>.PKG</code>. Você, também, deveria escolher a arquitetura correta, dependendo do Chip do seu sistema:</p><ul><li>Se você tiver um Chip Apple da Série M (M-Series Chip), escolha <code>aarch64</code> (Padrão)</li><li>Se você tiver um Chip Intel, escolha <code>x64</code></li><li>Siga essas [instruções para saber qual chip está em seu Mac] (<a href="https://support.apple.com/en-us/116943" target="_blank" rel="noreferrer">https://support.apple.com/en-us/116943</a>)</li></ul><p>Após baixar o instalador <code>.pkg</code>, execute-o e siga essas instruções:</p><p><img src="/assets/players/installing-java/macos-installer.png" alt="Instalador do Temurin Java" loading="lazy"></p><p>Você terá que digitar a sua senha de Administrador para completar a instalação:</p><p><img src="/assets/players/installing-java/macos-password-prompt.png" alt="macOS senha comando" loading="lazy"></p><h3 id="using-homebrew" tabindex="-1">Usando o Homebrew <a class="header-anchor" href="#using-homebrew" aria-label="Permalink to “Usando o Homebrew”">​</a></h3><p>Se você já tiver o <a href="https://brew.sh" target="_blank" rel="noreferrer">Homebrew</a> instalado, você pode instalar o Java 21 usando <code>brew</code>:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> temurin@21</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="3-verify-that-java-is-installed" tabindex="-1">3. Certifique-se de que a versão do Java 21 esteja instalada <a class="header-anchor" href="#3-verify-that-java-is-installed" aria-label="Permalink to “3. Certifique-se de que a versão do Java 21 esteja instalada”">​</a></h2><p>Uma vez que a instalação esteja completa, você pode verificar que o Java está devidamente instalado, ao abrir o Terminal novamente e digitar <code>$(/usr/libexec/java_home -v 21)/bin/java --version</code>.</p><p>Se o comando for executado corretamente, você verá o seguinte:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>openjdk 21.0.9 2025-10-21 LTS</span></span>
<span class="line"><span>OpenJDK Runtime Environment Temurin-21.0.9+10 (build 21.0.9+10-LTS)</span></span>
<span class="line"><span>OpenJDK 64-Bit Server VM Temurin-21.0.9+10 (build 21.0.9+10-LTS, mixed mode, sharing)</span></span></code></pre></div><p>Se você encontrar problemas, sinta-se a vontade para pedir ajuda em <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Discord do Fabric</a> no canal <code>#player-support</code>.</p>`,27)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};